-{"id":"beads_rust-0v1.3.3","title":"Regression test: sync never runs git or creates commits","description":"Add a regression test that asserts no git commands are executed during br sync. This can be done via instrumentation/mocking or by validating that no new git commits or staged changes appear after running sync.","acceptance_criteria":"- Sync path contains no git invocations\n- Test fails if a commit or staging change occurs","notes":"The incident class involved sync producing a destructive commit; this test blocks any future git integration.","status":"open","priority":1,"issue_type":"task","owner":"jeff141421@gmail.com","created_at":"2026-01-16T13:04:40.786138866-05:00","created_by":"Dicklesworthstone","updated_at":"2026-01-16T13:04:40.786138866-05:00","dependencies":[{"issue_id":"beads_rust-0v1.3.3","depends_on_id":"beads_rust-0v1.3","type":"parent-child","created_at":"2026-01-16T13:04:40.78869705-05:00","created_by":"Dicklesworthstone"},{"issue_id":"beads_rust-0v1.3.3","depends_on_id":"beads_rust-0v1.2.4","type":"blocks","created_at":"2026-01-16T13:05:48.785263655-05:00","created_by":"Dicklesworthstone"}]}
